import { useCallback } from 'react';
import type { AlpacaService } from '@/services/stocks';
import type { Position } from '@/types';

interface LayeredStopsParams {
  symbol: string;
  side: 'buy' | 'sell';
  qty: number;
  isCrypto: boolean;
  initialStopId: string | null;
  initialStopPrice: number;
  entryFillPrice: number;
  l2TrailPct: number;
  l3TrailPct: number;
  layer2Enabled?: boolean;
  layer3Enabled?: boolean;
}

interface UseLayeredStopsParams {
  service: AlpacaService;
  positions: Position[];
  realtimePrices: Record<string, number>;
  layeredSymbolsRef: React.MutableRefObject<Set<string>>;
}

export function useLayeredStops({ service, positions: _positions, realtimePrices: _realtimePrices, layeredSymbolsRef }: UseLayeredStopsParams) {
  const startLayeredStops = useCallback(async (params: LayeredStopsParams) => {
    // Mark symbol as having layered stops active
    layeredSymbolsRef.current.add(params.symbol);
    console.log('Layered stops started', params);
    return { success: true };
  }, [service, layeredSymbolsRef]);

  return { startLayeredStops };
}